def merge(intervals):
    if not intervals:
        return []
    s = sorted(intervals)
    result = [list(s[0])]
    for start, end in s[1:]:
        if start < result[-1][1]:
            result[-1][1] = max(result[-1][1], end)
        else:
            result.append([start, end])
    return [tuple(x) for x in result]
